"use strict";(self.webpackChunkmd_vuepress=self.webpackChunkmd_vuepress||[]).push([[9817],{32076:(e,a,s)=>{s.r(a),s.d(a,{data:()=>n});const n={key:"v-731785f8",path:"/superpowers/specs/2026-06-14-ai-reading-assistant-optimization-design.html",title:"AI 阅读助手优化设计",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"背景",slug:"背景",children:[]},{level:2,title:"目标",slug:"目标",children:[]},{level:2,title:"非目标",slug:"非目标",children:[]},{level:2,title:"总体架构",slug:"总体架构",children:[{level:3,title:"VuePress 前端",slug:"vuepress-前端",children:[]},{level:3,title:"NestJS 后端",slug:"nestjs-后端",children:[]},{level:3,title:"构建期摘要",slug:"构建期摘要",children:[]}]},{level:2,title:"交互设计",slug:"交互设计",children:[{level:3,title:"面板",slug:"面板",children:[]},{level:3,title:"消息流",slug:"消息流",children:[]},{level:3,title:"输入区",slug:"输入区",children:[]}]},{level:2,title:"对话协议",slug:"对话协议",children:[]},{level:2,title:"Token 优化",slug:"token-优化",children:[]},{level:2,title:"构建缓存设计",slug:"构建缓存设计",children:[{level:3,title:"缓存结构",slug:"缓存结构",children:[]},{level:3,title:"恢复与失效",slug:"恢复与失效",children:[]},{level:3,title:"可观测性",slug:"可观测性",children:[]}]},{level:2,title:"错误处理",slug:"错误处理",children:[]},{level:2,title:"测试策略",slug:"测试策略",children:[{level:3,title:"VuePress",slug:"vuepress",children:[]},{level:3,title:"NestJS",slug:"nestjs",children:[]},{level:3,title:"测试环境验收",slug:"测试环境验收",children:[]}]},{level:2,title:"发布与兼容",slug:"发布与兼容",children:[]}],git:{updatedTime:1781403093e3},filePathRelative:"superpowers/specs/2026-06-14-ai-reading-assistant-optimization-design.md"}},57794:(e,a,s)=>{s.r(a),s.d(a,{default:()=>t});const n=(0,s(66252).uE)('<h1 id="ai-阅读助手优化设计" tabindex="-1"><a class="header-anchor" href="#ai-阅读助手优化设计" aria-hidden="true">#</a> AI 阅读助手优化设计</h1><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景" aria-hidden="true">#</a> 背景</h2><p>当前 AI 阅读助手已支持文章摘要、文章/模块范围切换、联网检索、会话缓存和后端对话接口，但仍有三个关键问题：</p><ol><li>前端收到完整响应后才模拟逐字显示，不是真正的网络流式对话。</li><li>每轮请求重复发送完整文章提示词和全部历史，输入 token 随对话线性增长。</li><li>构建缓存从线上恢复时只恢复摘要，不恢复 manifest，缓存目录丢失后仍会重新分析全部 Markdown。</li></ol><p>本设计在保留 VuePress 2 + NestJS 架构的前提下完成增量优化，不迁移到新的 Chat 框架，也不引入账号系统。</p><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标" aria-hidden="true">#</a> 目标</h2><ul><li>桌面端提供接近主流开源 Chat 的右侧抽屉交互，移动端使用全屏面板。</li><li>对话采用真实流式响应，支持停止生成、重新生成、清空会话和错误重试。</li><li>限制重复上下文和历史消息，降低多轮对话 token 消耗。</li><li>未修改 Markdown 在后续构建中严格复用 AI 分析结果。</li><li>在 Vercel Preview 和站点测试部署中完成端到端验证。</li></ul><h2 id="非目标" tabindex="-1"><a class="header-anchor" href="#非目标" aria-hidden="true">#</a> 非目标</h2><ul><li>不增加登录、用户账户或跨设备会话同步。</li><li>不新增 Supabase Chat 会话表。</li><li>不替换现有 AI Provider，也不迁移整个站点到 Vercel AI SDK。</li><li>不改变现有 <code>/api/ai/chat</code> 和 OpenAI 兼容接口的行为。</li></ul><h2 id="总体架构" tabindex="-1"><a class="header-anchor" href="#总体架构" aria-hidden="true">#</a> 总体架构</h2><h3 id="vuepress-前端" tabindex="-1"><a class="header-anchor" href="#vuepress-前端" aria-hidden="true">#</a> VuePress 前端</h3><ul><li>将现有正文分栏改为覆盖式右侧抽屉，关闭后正文恢复完整宽度。</li><li><code>AIChatPanel</code> 管理流式消息、停止、重试、重新生成和本地会话。</li><li>对话历史按文章路径保存在浏览器本地，仅保存可恢复的最终消息。</li><li>请求只携带最近 6 轮对话；摘要消息、错误消息和 UI 状态不进入模型历史。</li><li>首轮携带压缩后的文章上下文，后续请求携带稳定的上下文标识和必要元数据。</li></ul><h3 id="nestjs-后端" tabindex="-1"><a class="header-anchor" href="#nestjs-后端" aria-hidden="true">#</a> NestJS 后端</h3><ul><li>保留 <code>POST /api/ai/chat</code>，新增 <code>POST /api/ai/chat/stream</code>。</li><li>流式接口返回 <code>text/event-stream</code>，事件类型为 <code>meta</code>、<code>delta</code>、<code>sources</code>、<code>usage</code>、<code>done</code> 和 <code>error</code>。</li><li>服务端统一裁剪历史、去重 system prompt、限制上下文长度和设置输出 token 上限。</li><li>OpenAI 兼容客户端支持上游 <code>stream: true</code>，解析并转发 SSE 数据。</li><li>Mock Provider 提供确定性的流式实现，供单元测试和 Preview 健康验证使用。</li></ul><h3 id="构建期摘要" tabindex="-1"><a class="header-anchor" href="#构建期摘要" aria-hidden="true">#</a> 构建期摘要</h3><ul><li>缓存键由规范化 Markdown 内容、摘要 prompt 版本、模型和提取版本共同计算。</li><li>manifest 与 summaries 必须作为同一缓存快照恢复和保存。</li><li>缓存恢复优先级为 GitHub Actions cache、本地缓存、线上静态缓存。</li><li>仅内容或分析配置哈希变化的文档进入 AI 调用队列。</li></ul><h2 id="交互设计" tabindex="-1"><a class="header-anchor" href="#交互设计" aria-hidden="true">#</a> 交互设计</h2><h3 id="面板" tabindex="-1"><a class="header-anchor" href="#面板" aria-hidden="true">#</a> 面板</h3><ul><li>桌面端宽度约 <code>min(560px, 46vw)</code>，从右侧滑入并带轻量遮罩。</li><li>移动端覆盖整个视口，保留安全区和返回/关闭按钮。</li><li>Header 显示当前文章标题、文章/模块作用域和清空会话入口。</li><li>打开、关闭、消息进入和 loading 使用 <code>transform</code>/<code>opacity</code> 动画，并支持 <code>prefers-reduced-motion</code>。</li></ul><h3 id="消息流" tabindex="-1"><a class="header-anchor" href="#消息流" aria-hidden="true">#</a> 消息流</h3><ul><li>首条助手消息为结构化文章摘要，不再用定时器模拟长时间打字。</li><li>流式回答创建一个空助手消息，收到 <code>delta</code> 后增量追加。</li><li>生成中发送按钮变为停止按钮；停止后保留已生成内容并标记为已中断。</li><li>每条助手回答提供复制和重新生成操作。</li><li>引用来源在回答完成后显示为紧凑链接列表。</li></ul><h3 id="输入区" tabindex="-1"><a class="header-anchor" href="#输入区" aria-hidden="true">#</a> 输入区</h3><ul><li>输入区固定在面板底部，自动扩展到限定高度。</li><li><code>Enter</code> 发送，<code>Shift+Enter</code> 换行。</li><li>显示当前作用域和联网状态，避免用户误判回答范围。</li></ul><h2 id="对话协议" tabindex="-1"><a class="header-anchor" href="#对话协议" aria-hidden="true">#</a> 对话协议</h2><p>请求示例：</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  <span class="token property">&quot;messages&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span> <span class="token property">&quot;role&quot;</span><span class="token operator">:</span> <span class="token string">&quot;user&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;content&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Fiber 解决了什么问题？&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;context&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token property">&quot;scope&quot;</span><span class="token operator">:</span> <span class="token string">&quot;article&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;pagePath&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/react/react16.md&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;title&quot;</span><span class="token operator">:</span> <span class="token string">&quot;React 16&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;tags&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;React&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;content&quot;</span><span class="token operator">:</span> <span class="token string">&quot;压缩后的文章正文&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;contentHash&quot;</span><span class="token operator">:</span> <span class="token string">&quot;sha256:...&quot;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;enableWebSearch&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>SSE 示例：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>event: meta\ndata: {&quot;provider&quot;:&quot;openai&quot;,&quot;model&quot;:&quot;deepseek-v4-pro&quot;}\n\nevent: delta\ndata: {&quot;content&quot;:&quot;Fiber&quot;}\n\nevent: usage\ndata: {&quot;promptTokens&quot;:820,&quot;completionTokens&quot;:156,&quot;totalTokens&quot;:976}\n\nevent: done\ndata: {}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>客户端必须容忍无 <code>usage</code> 的 Provider。流式接口失败时显示可重试状态，不自动重复请求，避免重复计费。</p><h2 id="token-优化" tabindex="-1"><a class="header-anchor" href="#token-优化" aria-hidden="true">#</a> Token 优化</h2><ul><li>客户端最多发送最近 12 条非 system 消息，即 6 轮对话。</li><li>服务端再次执行字符预算裁剪，不能信任客户端限制。</li><li>system prompt 由服务端生成；前端不再每轮发送完整 system prompt。</li><li>文章正文在首轮或内容哈希变化时发送，正文进行空白规范化和长度限制。</li><li>模块模式只发送高相关度的模块索引摘要，不拼接所有文档全文。</li><li>默认设置合理的 <code>max_tokens</code>，联网搜索只注入标题、URL 和短摘要。</li><li>返回 usage 并记录结构化日志，用于比较优化前后的 token 消耗。</li></ul><h2 id="构建缓存设计" tabindex="-1"><a class="header-anchor" href="#构建缓存设计" aria-hidden="true">#</a> 构建缓存设计</h2><h3 id="缓存结构" tabindex="-1"><a class="header-anchor" href="#缓存结构" aria-hidden="true">#</a> 缓存结构</h3><p>manifest 版本升级，单文件条目包含：</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  <span class="token property">&quot;sourceHash&quot;</span><span class="token operator">:</span> <span class="token string">&quot;sha256:...&quot;</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;analysisHash&quot;</span><span class="token operator">:</span> <span class="token string">&quot;sha256:...&quot;</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;model&quot;</span><span class="token operator">:</span> <span class="token string">&quot;deepseek-v4-pro&quot;</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;promptVersion&quot;</span><span class="token operator">:</span> <span class="token string">&quot;summary-v2&quot;</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;processedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;...&quot;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><code>analysisHash</code> 覆盖内容提取版本、prompt 版本和模型，避免配置变化后错误复用。</p><h3 id="恢复与失效" tabindex="-1"><a class="header-anchor" href="#恢复与失效" aria-hidden="true">#</a> 恢复与失效</h3><ul><li>线上 <code>summaries.json</code> 的 <code>_meta</code> 中携带可重建 manifest 所需的每文件分析哈希。</li><li>恢复脚本同时写入 <code>summaries.json</code> 和 <code>manifest.json</code>。</li><li>Git diff 仅作为加速提示，内容/分析哈希是最终判定依据；提交变化但内容哈希一致时仍复用缓存。</li><li>失败占位不作为永久成功缓存，后续构建应重试。</li><li>删除的 Markdown 同步移除摘要和 manifest 条目。</li></ul><h3 id="可观测性" tabindex="-1"><a class="header-anchor" href="#可观测性" aria-hidden="true">#</a> 可观测性</h3><p>每次构建输出：总文件数、命中数、失效数、AI 调用数、失败数、命中率和处理耗时。增加 dry-run 模式，在不调用 AI 的情况下打印处理计划。</p><h2 id="错误处理" tabindex="-1"><a class="header-anchor" href="#错误处理" aria-hidden="true">#</a> 错误处理</h2><ul><li>用户停止生成使用 <code>AbortController</code>，不显示网络错误提示。</li><li>SSE 中断保留部分内容并提供重新生成。</li><li>上游错误状态和简短错误正文继续透传，但不暴露密钥或完整 Provider 响应。</li><li>摘要缓存恢复失败时继续构建，并明确记录将触发的 AI 调用数量。</li><li>未配置 AI Key 时保留已有静态摘要，不用空输出覆盖可用缓存。</li></ul><h2 id="测试策略" tabindex="-1"><a class="header-anchor" href="#测试策略" aria-hidden="true">#</a> 测试策略</h2><h3 id="vuepress" tabindex="-1"><a class="header-anchor" href="#vuepress" aria-hidden="true">#</a> VuePress</h3><ul><li>为缓存规划、manifest 恢复、失败重试和零调用复用增加 Node 测试。</li><li>扩展 AI bundle smoke test，检查流式接口、停止按钮和抽屉样式。</li><li>运行 <code>npm run build</code>，并在本地浏览器验证桌面和移动断点。</li></ul><h3 id="nestjs" tabindex="-1"><a class="header-anchor" href="#nestjs" aria-hidden="true">#</a> NestJS</h3><ul><li>单测历史裁剪、上下文注入、SSE 解析和 usage 映射。</li><li>E2E 验证 Mock 流事件顺序、停止连接、旧 JSON 接口兼容。</li><li>运行 <code>npm test</code>、<code>npm run typecheck</code> 和 <code>npm run build</code>。</li></ul><h3 id="测试环境验收" tabindex="-1"><a class="header-anchor" href="#测试环境验收" aria-hidden="true">#</a> 测试环境验收</h3><ul><li>后端部署到 Vercel Preview，验证 <code>/api/ai/chat/stream</code> 返回真实流式事件。</li><li>VuePress 测试部署指向 Preview API，验证摘要、连续追问、停止、重试、来源和移动端面板。</li><li>连续运行两次相同构建，第二次必须报告未修改 Markdown 的 AI 调用数为 0。</li><li>修改一个 Markdown 后构建，只允许该文件进入 AI 调用队列。</li><li>对同一问题记录优化前后请求体大小和 usage，确认输入 token 明显下降。</li></ul><h2 id="发布与兼容" tabindex="-1"><a class="header-anchor" href="#发布与兼容" aria-hidden="true">#</a> 发布与兼容</h2><ul><li>新流式接口独立上线，旧客户端不受影响。</li><li>前端可在流式接口不可用时显示错误并允许手动重试，不静默切换导致重复计费。</li><li>Preview 验收通过后再合并或发布生产环境。</li></ul>',51),l={},t=(0,s(83744).Z)(l,[["render",function(e,a){return n}]])},83744:(e,a)=>{a.Z=(e,a)=>{const s=e.__vccOpts||e;for(const[e,n]of a)s[e]=n;return s}}}]);